async def generate_data():
  for i in range(1000):
    yield f'data chunk {i}\n'
    await asyncio.sleep(0.01)

@app.get('/stream')
async def stream():
  return StreamingResponse(
    generate_data(),
    media_type='text/plain'
  )"]

